const fs = require(''fs'')
const path = require(''path'')

const root = process.cwd()

function write(rel, content) {
  const full = path.join(root, rel)
  fs.mkdirSync(path.dirname(full), { recursive: true })
  if (fs.existsSync(full)) {
    fs.copyFileSync(full, `${full}.backup-food-funcional-${new Date().toISOString().replace(/[-:TZ.]/g, '''').slice(0, 14)}`)
  }
  fs.writeFileSync(full, content, ''utf8'')
  console.log(`Atualizado: ${rel}`)
}

function read(rel) {
  const full = path.join(root, rel)
  return fs.existsSync(full) ? fs.readFileSync(full, ''utf8'') : ''''
}

function patchPanelModules() {
  const rel = ''lib/panel-modules.ts''
  const full = path.join(root, rel)
  if (!fs.existsSync(full)) return
  let content = fs.readFileSync(full, ''utf8'')
  const before = content

  const replacements = [
    [/href:\s*[''"]\/painel\/modulos\/taxas-entrega[''"]/g, "href: ''/painel/taxas-entrega''"],
    [/href:\s*[''"]\/painel\/modulos\/horarios[''"]/g, "href: ''/painel/horarios''"],
    [/href:\s*[''"]\/painel\/modulos\/entregas[''"]/g, "href: ''/painel/entregas''"],
    [/href:\s*[''"]\/painel\/modulos\/formas-pagamento[''"]/g, "href: ''/painel/formas-pagamento''"],
    [/fallbackHref:\s*[''"]\/painel\/modulos\/taxas-entrega[''"]/g, "fallbackHref: ''/painel/taxas-entrega''"],
    [/fallbackHref:\s*[''"]\/painel\/modulos\/horarios[''"]/g, "fallbackHref: ''/painel/horarios''"],
    [/fallbackHref:\s*[''"]\/painel\/modulos\/entregas[''"]/g, "fallbackHref: ''/painel/entregas''"],
    [/fallbackHref:\s*[''"]\/painel\/modulos\/formas-pagamento[''"]/g, "fallbackHref: ''/painel/formas-pagamento''"],
  ]

  for (const [pattern, replacement] of replacements) {
    content = content.replace(pattern, replacement)
  }

  // Garante que a lista de rotas conhecidas aceita Food funcional, sem duplicar se já existir.
  const knownRoutes = [
    ''/painel/entregas'',
    ''/painel/horarios'',
    ''/painel/taxas-entrega'',
    ''/painel/formas-pagamento'',
  ]

  for (const route of knownRoutes) {
    if (!content.includes(`''${route}''`) && !content.includes(`"${route}"`)) {
      content = content.replace(/(export\s+const\s+knownExistingPanelRoutes\s*=\s*\[[\s\S]*?)(\n\])/m, `$1\n  ''${route}'',$2`)
    }
  }

  if (content !== before) {
    fs.copyFileSync(full, `${full}.backup-food-menu-${new Date().toISOString().replace(/[-:TZ.]/g, '''').slice(0, 14)}`)
    fs.writeFileSync(full, content, ''utf8'')
    console.log(''Atualizado: lib/panel-modules.ts'')
  } else {
    console.log(''Sem alteração: lib/panel-modules.ts'')
  }
}

